-- Check reimbursement_items table (what the digest currently counts)
SELECT COUNT(*) as reimbursement_items_paid_this_week
FROM reimbursement_items
WHERE status = 'paid'
  AND updated_at >= UNIX_TIMESTAMP(DATE_SUB(NOW(), INTERVAL 7 DAY)) * 1000;

-- Check all reimbursement-related tables
SELECT COUNT(*) as reimbursement_items_total FROM reimbursement_items;

-- Check what statuses exist
SELECT status, COUNT(*) as cnt FROM reimbursement_items GROUP BY status;

